// Generates the Python hashlib.sha3_256 demo shown on the Done step.

export function full_script(state) {
  const messageLiteral = JSON.stringify(state.sha_message ?? "hello, world");
  return [
    "# SHA-3 (Keccak) demo — generated by cloak.moosha.org",
    "# hashlib ships with Python — no third-party install required.",
    "# hashlib.sha3_256 was added in Python 3.6 (2016).",
    "#",
    "# Why use SHA-3 instead of SHA-256?",
    "#   - Cryptographic hedge. SHA-2 and SHA-3 are built on entirely different",
    "#     constructions (Merkle-Damgård vs sponge). If a structural weakness is",
    "#     ever found in one family, the other is unaffected.",
    "#   - Length-extension immunity. SHA-256/SHA-512 are vulnerable to length-",
    "#     extension attacks; SHA-3 is not, because the capacity portion of the",
    "#     sponge state never leaves the box.",
    "#   - Ethereum and a few other ecosystems use Keccak-256 (the pre-FIPS-202",
    "#     variant — same permutation, different padding byte).",
    "",
    "import hashlib",
    "",
    "# 1. Hash your message with SHA3-256.",
    `message = b${messageLiteral}`,
    "digest = hashlib.sha3_256(message).hexdigest()",
    'print("message  :", message.decode())',
    'print("sha3-256 :", digest)',
    "",
    "# 2. The canonical empty-string FIPS 202 test vector — every SHA3-256",
    "#    implementation produces the same value for this input.",
    'empty = hashlib.sha3_256(b"").hexdigest()',
    'assert empty == "a7ffc6f8bf1ed76651c14756a061d662f580ff4de43b49fa82d80a4b80f8434a"',
    'print("sha3-256(\\"\\"):", empty)',
    "",
    "# 3. Side-by-side with SHA-256 — same input, completely different digests.",
    "#    Different construction → no structural overlap between the outputs.",
    'msg = b"abc"',
    'print("sha-256  :", hashlib.sha256(msg).hexdigest())',
    'print("sha3-256 :", hashlib.sha3_256(msg).hexdigest())',
    "",
    "# 4. Ethereum's 'Keccak-256' is NOT exactly hashlib.sha3_256 — it uses the",
    "#    original Keccak padding (0x01) instead of the FIPS-202 SHA-3 padding",
    "#    (0x06). For Ethereum work you need pycryptodome's keccak module or",
    "#    eth_hash; the stdlib sha3_256 will give DIFFERENT digests.",
    "#    from Crypto.Hash import keccak",
    "#    eth_digest = keccak.new(digest_bits=256, data=msg).hexdigest()",
  ].join("\n");
}

